def _strip_comments(sql: str) -> str:
    sql = re.sub(r"/\*.*?\*/", " ", sql, flags=re.DOTALL)  # /* block */
    return re.sub(r"--[^\n]*", " ", sql)  # -- line


def _strip_quoted(sql: str) -> str:
    """Blank out string literals + quoted identifiers so their contents can't be
    mistaken for SQL keywords or statement separators."""
    sql = re.sub(r"'(?:[^']|'')*'", " ", sql)  # 'single' strings ('' escape)
    sql = re.sub(r'"(?:[^"]|"")*"', " ", sql)  # "quoted" identifiers
    return re.sub(r"`[^`]*`", " ", sql)  # `backtick` identifiers (Databricks/UC)

